export const CTAGroupLayouts = ["auto", "horizontal", "vertical"] as const;

export const CTAGroupOrientationValues = {
  horizontal: "horizontal",
  vertical: "vertical",
} as const;

type CTAGroupOrientation = keyof typeof CTAGroupOrientationValues;

export type CTAGroupOrientationClass =
  | "orientation-horizontal"
  | "orientation-vertical";

export const CTA_GROUP_ORIENTATION_CLASSES: Record<
  CTAGroupOrientation,
  CTAGroupOrientationClass
> = {
  horizontal: "orientation-horizontal",
  vertical: "orientation-vertical",
};

export type CTAGroupLayout = (typeof CTAGroupLayouts)[number];

export const DEFAULT_CTA_GROUP_LAYOUT: CTAGroupLayout = "auto";
