import { CTA_GROUP_ORIENTATION_CLASSES } from "./CTAGroup.config";

/**
 * Calculates the minimum width needed to display the CTAGroup content
 * in horizontal layout.
 *
 * Temporarily applies the horizontal orientation class and intrinsic width
 * to measure the true width needed, then restores the original state.
 */
export const calculateMinHorizontalWidth = (
  element: HTMLDivElement
): number => {
  if (element.children.length === 0) return 0;

  const horizontalClass = CTA_GROUP_ORIENTATION_CLASSES.horizontal;
  const verticalClass = CTA_GROUP_ORIENTATION_CLASSES.vertical;
  const hadHorizontalClass = element.classList.contains(horizontalClass);
  const hadVerticalClass = element.classList.contains(verticalClass);
  const originalWidth = element.style.width;

  // Temporarily apply horizontal layout with intrinsic width
  // Remove vertical class to ensure we measure true horizontal state
  element.classList.remove(verticalClass);
  element.classList.add(horizontalClass);
  element.style.width = "max-content";

  // Force a reflow to ensure styles are applied before measuring
  // Reading offsetWidth triggers a synchronous reflow
  const minWidth = element.offsetWidth;

  // Restore original state
  if (!hadHorizontalClass) {
    element.classList.remove(horizontalClass);
  }
  if (hadVerticalClass) {
    element.classList.add(verticalClass);
  }
  element.style.width = originalWidth;

  return minWidth;
};
